// // This module synchronizes data_in with data_out on the falling edge of the clock when out_en is high.
module GPIO_Controller (
    input wire clk,
    input wire out_en,
    input wire [3:0] data_in,
    output reg [3:0] data_out
);

    always @(posedge clk) begin
        if (out_en) begin
            data_out <= data_in;
        end
    end

endmodule
